@startuml
!theme plain
skinparam packageStyle rectangle
skinparam classStyle rectangle
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

package "com" {
  package "qinzhu" {
    package "bean" {
      class Borrow {
        - BorrowId id
        - Integer punishid
        - Boolean isreturn
        - Boolean isrenew
        - Date time
      }

      class BorrowId {
        - Integer bookid
        - Integer readerid
      }

      class ReaderCat {
        - Integer id
        - String name
      }

      class Reader {
        - Integer id
        - Integer readercat
        - Integer studentno
        - String password
        - String name
        - String sex
        - String belong
        - Integer borrowcount
        - String picture
      }

      class Punish {
        - Integer id
        - Integer hourlong
        - Float fine
      }

      class BookCat {
        - Integer id
        - Integer parentid
        - Boolean isparent
        - String name
      }

      class Book {
        - Integer id
        - Integer bookcat
        - String bookname
        - String isbn
        - String publish
        - Date pubdate
      }
    }
  }
}

Borrow "1" *-- "1" BorrowId
Borrow "1" *-- "1" ReaderCat
Reader "1" *-- "1" Punish
Reader "1" *-- "1" BookCat
Reader "1" *-- "1" Book

@enduml
